function ContactSalesModal({ onClose }) {
  const [form, setForm] = useState({ name: '', company: '', email: '', employees: '500-2000', message: '' });
  const [sent, setSent] = useState(false);
  const [sending, setSending] = useState(false);

  const handleSend = () => {
    if (!form.name || !form.email) return;
    setSending(true);
    setTimeout(() => { setSending(false); setSent(true); }, 1500);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-[#1a2035] border border-white/10 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-8 py-6 border-b border-white/10">
          <div>
            <h2 className="text-xl font-bold text-white">Talk to Sales</h2>
            <p className="text-sm text-gray-400 mt-0.5">Custom Enterprise plan — tailored for your team</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-white p-2 rounded-lg hover:bg-white/10 transition-all"><X size={20} /></button>
        </div>
        {sent ? (
          <div className="px-8 py-12 text-center">
            <div className="w-16 h-16 rounded-full bg-green-500/20 flex items-center justify-center mx-auto mb-4">
              <Check size={32} className="text-green-400" />
            </div>
            <h3 className="text-xl font-bold text-white mb-2">Request Sent!</h3>
            <p className="text-gray-400 text-sm">Our enterprise team will reach out within 24 hours at <strong className="text-white">{form.email}</strong></p>
            <button onClick={onClose} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-all">Close</button>
          </div>
        ) : (
          <>
            <div className="px-8 py-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1 block">Full Name *</label>
                  <input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="Anant Prabhu" className="w-full px-4 py-2.5 rounded-xl border border-white/10 bg-white/5 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1 block">Company</label>
                  <input value={form.company} onChange={e => setForm(f => ({ ...f, company: e.target.value }))} placeholder="Acme Corp" className="w-full px-4 py-2.5 rounded-xl border border-white/10 bg-white/5 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1 block">Work Email *</label>
                <input type="email" value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} placeholder="you@company.com" className="w-full px-4 py-2.5 rounded-xl border border-white/10 bg-white/5 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1 block">Team Size</label>
                <select value={form.employees} onChange={e => setForm(f => ({ ...f, employees: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-white/10 bg-[#1a2035] text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none">
                  {['1-50', '50-200', '200-500', '500-2000', '2000+'].map(v => <option key={v} value={v}>{v} employees</option>)}
                </select>
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1 block">Message (optional)</label>
                <textarea value={form.message} onChange={e => setForm(f => ({ ...f, message: e.target.value }))} rows={3} placeholder="Tell us about your use case..." className="w-full px-4 py-2.5 rounded-xl border border-white/10 bg-white/5 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none" />
              </div>
            </div>
            <div className="px-8 py-5 border-t border-white/10 flex gap-3 justify-end">
              <button onClick={onClose} className="px-5 py-2 text-sm font-bold text-gray-300 bg-white/10 rounded-xl hover:bg-white/20 transition-all">Cancel</button>
              <button onClick={handleSend} disabled={sending || !form.name || !form.email}
                className="px-6 py-2 text-sm font-bold text-white bg-indigo-600 hover:bg-indigo-700 rounded-xl transition-all active:scale-95 disabled:opacity-50 flex items-center gap-2">
                {sending ? 'Sending...' : <><Mail size={15} /> Send Request</>}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

