import React, { useState, useEffect } from 'react';
import { Building2, Crown, Activity, Users, Plus, Settings, CreditCard, Trash2, MoreVertical, X, Check } from 'lucide-react';

const REGIONS = ['North America', 'Europe', 'Asia', 'South America', 'Middle East'];
const INDUSTRIES = ['Logistics', 'Aerospace', 'FinTech', 'Healthcare', 'SaaS', 'Retail', 'Education'];
const PLAN_TIERS = ['Enterprise', 'Professional', 'Free Tier'];

function generateOrg(id) {
  const name = `Org_${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
  const region = REGIONS[Math.floor(Math.random() * REGIONS.length)];
  const industry = INDUSTRIES[Math.floor(Math.random() * INDUSTRIES.length)];
  const tier = PLAN_TIERS[Math.floor(Math.random() * PLAN_TIERS.length)];
  const maxSeats = tier === 'Enterprise' ? 200 : tier === 'Professional' ? 50 : 5;
  const usedSeats = Math.floor(Math.random() * maxSeats);
  const scans = Math.floor(Math.random() * 1500000);
  const statuses = tier === 'Free Tier' ? ['Inactive'] : ['Active', 'Active', 'Delinquent', 'Active'];
  const status = statuses[Math.floor(Math.random() * statuses.length)];
  return { id, name, region, industry, tier, maxSeats, usedSeats, scans, status };
}

const INITIAL_ORGS = [
